{
  "name": "Thiia AI",
  "description": "A browser-based AI-powered development environment featuring code execution, intelligent chat assistance with multiple Gemini models (Flash Lite & Pro), and project management."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface User {
  id: string;
  email: string;
  name: string;
  avatarUrl?: string;
}

export interface Project {
  id: string;
  name: string;
  description: string;
  language: 'javascript' | 'typescript' | 'python' | 'html';
  lastModified: number;
}

export interface File {
  id: string;
  projectId: string;
  name: string;
  content: string;
  language: string;
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'assistant';
  content: string;
  model: string;
  timestamp: number;
  thinking?: boolean;
}

export type AIComplexity = 'low' | 'high' | 'research';

export interface ExecutionResult {
  output: string;
  error?: string;
  executionTime: string;
}

import { GoogleGenAI } from "@google/genai";
import { AIComplexity } from "../types";

// Initialize Gemini Client
// IMPORTANT: The API key is injected via process.env.API_KEY
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateResponse = async (
  prompt: string,
  contextCode: string,
  complexity: AIComplexity,
  history: { role: string; parts: { text: string }[] }[] = []
): Promise<string> => {
  try {
    let modelName = 'gemini-2.5-flash-lite-latest'; // Default for low complexity/fast response
    let thinkingBudget = 0;

    if (complexity === 'high') {
      modelName = 'gemini-3-pro-preview';
      thinkingBudget = 32768; // Max budget for deep reasoning
    } else if (complexity === 'research') {
      // Use standard pro for research without forced thinking or just standard flash if speed preferred
      // Using 3-flash for balanced research
      modelName = 'gemini-3-flash-preview'; 
    }

    const config: any = {
      systemInstruction: `You are Thiia AI, an advanced intelligent coding assistant. 
      Current Context Code:
      \`\`\`
      ${contextCode}
      \`\`\`
      Always provide concise, correct, and safe code. 
      If in 'High' complexity mode, think deeply before answering.
      If in 'Research' mode, be thorough and explanatory.
      `,
    };

    if (thinkingBudget > 0) {
      config.thinkingConfig = { thinkingBudget };
    }

    // Prepare contents including history
    // Note: for this simple stateless implementation we might just send the last prompt + context
    // But let's respect the chat structure if possible.
    // For simplicity in this demo, we'll use a direct generateContent for the latest turn 
    // to allow easy model switching per message without managing multi-model chat sessions.

    const response = await ai.models.generateContent({
      model: modelName,
      contents: prompt,
      config: config
    });

    return response.text || "No response generated.";

  } catch (error: any) {
    console.error("Gemini API Error:", error);
    return `Error: ${error.message || "Failed to generate response."}`;
  }
};

import { Project, File, User } from "../types";

const PROJECTS_KEY = 'thiia_projects';
const FILES_KEY = 'thiia_files';

// Initial Seed Data
const INITIAL_PROJECTS: Project[] = [
  { id: '1', name: 'React Demo', description: 'A simple counter app', language: 'javascript', lastModified: Date.now() },
  { id: '2', name: 'Python Script', description: 'Data processing utility', language: 'python', lastModified: Date.now() - 100000 },
];

const INITIAL_FILES: File[] = [
  { id: 'f1', projectId: '1', name: 'App.js', language: 'javascript', content: "function App() {\n  const [count, setCount] = React.useState(0);\n  return <div>Hello Thiia! Count: {count}</div>;\n}" },
  { id: 'f2', projectId: '1', name: 'utils.js', language: 'javascript', content: "export const add = (a, b) => a + b;" },
  { id: 'f3', projectId: '2', name: 'main.py', language: 'python', content: "def main():\n    print('Hello from Python world!')\n\nif __name__ == '__main__':\n    main()" },
];

export const getProjects = (): Project[] => {
  const stored = localStorage.getItem(PROJECTS_KEY);
  if (!stored) {
    localStorage.setItem(PROJECTS_KEY, JSON.stringify(INITIAL_PROJECTS));
    localStorage.setItem(FILES_KEY, JSON.stringify(INITIAL_FILES));
    return INITIAL_PROJECTS;
  }
  return JSON.parse(stored);
};

export const createProject = (name: string, description: string, language: Project['language']): Project => {
  const projects = getProjects();
  const newProject: Project = {
    id: crypto.randomUUID(),
    name,
    description,
    language,
    lastModified: Date.now(),
  };
  projects.push(newProject);
  localStorage.setItem(PROJECTS_KEY, JSON.stringify(projects));

  // Create default file
  createFile(newProject.id, language === 'python' ? 'main.py' : 'index.js', language, language === 'python' ? 'print("Hello World")' : 'console.log("Hello World");');

  return newProject;
};

export const deleteProject = (id: string) => {
  const projects = getProjects().filter(p => p.id !== id);
  localStorage.setItem(PROJECTS_KEY, JSON.stringify(projects));
};

export const getFiles = (projectId: string): File[] => {
  const stored = localStorage.getItem(FILES_KEY);
  const allFiles: File[] = stored ? JSON.parse(stored) : INITIAL_FILES;
  return allFiles.filter(f => f.projectId === projectId);
};

export const createFile = (projectId: string, name: string, language: string, content: string = '') => {
  const stored = localStorage.getItem(FILES_KEY);
  const allFiles: File[] = stored ? JSON.parse(stored) : INITIAL_FILES;
  const newFile: File = { id: crypto.randomUUID(), projectId, name, language, content };
  allFiles.push(newFile);
  localStorage.setItem(FILES_KEY, JSON.stringify(allFiles));
  return newFile;
};

export const updateFileContent = (fileId: string, content: string) => {
  const stored = localStorage.getItem(FILES_KEY);
  const allFiles: File[] = stored ? JSON.parse(stored) : INITIAL_FILES;
  const index = allFiles.findIndex(f => f.id === fileId);
  if (index !== -1) {
    allFiles[index].content = content;
    localStorage.setItem(FILES_KEY, JSON.stringify(allFiles));
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { User, Project, File, ChatMessage, AIComplexity } from './types';
import * as db from './services/mockDb';
import { generateResponse } from './services/geminiService';

// --- Icons ---
const Icon = ({ name, className = "" }: { name: string; className?: string }) => (
  <i className={`fa-solid fa-${name} ${className}`}></i>
);

// --- Components ---

const Sidebar = ({ 
  projects, 
  activeProject, 
  onSelectProject, 
  onCreateProject, 
  onLogout 
}: { 
  projects: Project[], 
  activeProject: Project | null, 
  onSelectProject: (p: Project) => void, 
  onCreateProject: () => void,
  onLogout: () => void
}) => (
  <div className="w-64 bg-zinc-900 border-r border-zinc-800 flex flex-col h-full">
    <div className="p-4 border-b border-zinc-800 flex items-center gap-2 text-indigo-400 font-bold text-xl">
      <Icon name="code-branch" />
      <span>Thiia AI</span>
    </div>

    <div className="flex-1 overflow-y-auto p-2">
      <div className="flex justify-between items-center px-2 py-2 mb-2">
        <span className="text-xs font-semibold text-zinc-500 uppercase">Projects</span>
        <button onClick={onCreateProject} className="text-zinc-400 hover:text-white transition">
          <Icon name="plus" />
        </button>
      </div>

      <div className="space-y-1">
        {projects.map(p => (
          <button
            key={p.id}
            onClick={() => onSelectProject(p)}
            className={`w-full text-left px-3 py-2 rounded-md text-sm transition flex items-center gap-2 ${
              activeProject?.id === p.id 
                ? 'bg-indigo-500/10 text-indigo-400 border border-indigo-500/20' 
                : 'text-zinc-400 hover:bg-zinc-800 hover:text-zinc-200'
            }`}
          >
            <Icon name={p.language === 'python' ? 'python' : 'js'} className="opacity-70" />
            <span className="truncate">{p.name}</span>
          </button>
        ))}
      </div>
    </div>

    <div className="p-4 border-t border-zinc-800">
      <button 
        onClick={onLogout}
        className="flex items-center gap-2 text-zinc-500 hover:text-red-400 transition text-sm w-full"
      >
        <Icon name="sign-out-alt" />
        <span>Sign Out</span>
      </button>
    </div>
  </div>
);

const FileTree = ({ 
  files, 
  activeFile, 
  onSelectFile,
  onCreateFile
}: { 
  files: File[], 
  activeFile: File | null, 
  onSelectFile: (f: File) => void,
  onCreateFile: () => void
}) => (
  <div className="w-56 bg-zinc-900 border-r border-zinc-800 flex flex-col">
    <div className="h-9 flex items-center justify-between px-4 border-b border-zinc-800">
      <span className="text-xs font-medium text-zinc-400">EXPLORER</span>
      <button onClick={onCreateFile} className="text-zinc-500 hover:text-zinc-300">
        <Icon name="file-circle-plus" />
      </button>
    </div>
    <div className="flex-1 overflow-y-auto py-2">
      {files.map(f => (
        <button
          key={f.id}
          onClick={() => onSelectFile(f)}
          className={`w-full text-left px-4 py-1.5 text-sm flex items-center gap-2 ${
            activeFile?.id === f.id ? 'bg-zinc-800 text-white' : 'text-zinc-500 hover:text-zinc-300'
          }`}
        >
          <Icon name="file-code" className="text-xs" />
          <span className="truncate">{f.name}</span>
        </button>
      ))}
    </div>
  </div>
);

const CodeEditor = ({ 
  file, 
  onChange 
}: { 
  file: File | null, 
  onChange: (val: string) => void 
}) => {
  if (!file) {
    return (
      <div className="flex-1 bg-zinc-950 flex flex-col items-center justify-center text-zinc-600">
        <Icon name="code" className="text-6xl mb-4 opacity-20" />
        <p>Select a file to start editing</p>
      </div>
    );
  }

  return (
    <div className="flex-1 flex flex-col bg-zinc-950 relative">
      <div className="h-9 bg-zinc-900 border-b border-zinc-800 flex items-center px-4 text-sm text-zinc-400">
        <Icon name="file" className="mr-2 opacity-50" />
        {file.name}
      </div>
      <textarea
        className="flex-1 w-full bg-[#1e1e1e] text-zinc-300 p-4 font-mono text-sm resize-none focus:outline-none leading-relaxed"
        value={file.content}
        onChange={(e) => onChange(e.target.value)}
        spellCheck={false}
      />
    </div>
  );
};

const Console = ({ output }: { output: string }) => (
  <div className="h-48 bg-zinc-900 border-t border-zinc-800 flex flex-col">
    <div className="h-8 flex items-center px-4 border-b border-zinc-800 bg-zinc-900/50">
      <span className="text-xs font-bold text-zinc-500">TERMINAL</span>
    </div>
    <div className="flex-1 p-3 font-mono text-xs overflow-y-auto text-zinc-300 whitespace-pre-wrap">
      {output || <span className="text-zinc-600 italic">Ready to execute...</span>}
    </div>
  </div>
);

const ChatInterface = ({ 
  messages, 
  onSendMessage, 
  isTyping 
}: { 
  messages: ChatMessage[], 
  onSendMessage: (msg: string, complexity: AIComplexity) => void,
  isTyping: boolean
}) => {
  const [input, setInput] = useState("");
  const [complexity, setComplexity] = useState<AIComplexity>('low');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim()) return;
    onSendMessage(input, complexity);
    setInput("");
  };

  return (
    <div className="w-96 bg-zinc-900 border-l border-zinc-800 flex flex-col h-full">
      <div className="h-12 border-b border-zinc-800 flex items-center justify-between px-4 bg-zinc-900/50">
        <span className="font-semibold text-zinc-300 flex items-center gap-2">
          <Icon name="robot" className="text-indigo-500" />
          AI Assistant
        </span>
        <div className="flex gap-1 bg-zinc-800 p-0.5 rounded-lg">
          <button 
            onClick={() => setComplexity('low')}
            title="Flash Lite (Fast)"
            className={`p-1.5 rounded text-xs transition ${complexity === 'low' ? 'bg-indigo-600 text-white' : 'text-zinc-400 hover:text-white'}`}
          >
            <Icon name="bolt" />
          </button>
          <button 
            onClick={() => setComplexity('high')}
            title="Gemini Pro (Deep Thinking)"
            className={`p-1.5 rounded text-xs transition ${complexity === 'high' ? 'bg-purple-600 text-white' : 'text-zinc-400 hover:text-white'}`}
          >
            <Icon name="brain" />
          </button>
          <button 
            onClick={() => setComplexity('research')}
            title="Research Mode"
            className={`p-1.5 rounded text-xs transition ${complexity === 'research' ? 'bg-teal-600 text-white' : 'text-zinc-400 hover:text-white'}`}
          >
            <Icon name="book-open" />
          </button>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-4" ref={scrollRef}>
        {messages.map(msg => (
          <div key={msg.id} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
            <div className={`max-w-[85%] rounded-lg p-3 text-sm leading-relaxed ${
              msg.role === 'user' 
                ? 'bg-indigo-600 text-white' 
                : 'bg-zinc-800 text-zinc-300 border border-zinc-700'
            }`}>
              {msg.role === 'assistant' && (
                <div className="text-[10px] text-zinc-500 mb-1 font-mono uppercase tracking-wider flex items-center gap-1">
                   <Icon name={msg.model.includes('pro') ? 'brain' : 'bolt'} />
                   {msg.model.replace('gemini-', '').replace('-preview', '').replace('-latest', '')}
                </div>
              )}
              <div className="whitespace-pre-wrap">{msg.content}</div>
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex items-center gap-2 text-zinc-500 text-xs pl-2">
            <Icon name="circle-notch" className="fa-spin" />
            <span>AI is thinking...</span>
          </div>
        )}
      </div>

      <form onSubmit={handleSubmit} className="p-4 border-t border-zinc-800 bg-zinc-900/50">
        <div className="relative">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder={`Ask ${complexity === 'low' ? 'Flash' : complexity === 'high' ? 'Deep Thinker' : 'Researcher'}...`}
            className="w-full bg-zinc-800 border border-zinc-700 text-zinc-200 text-sm rounded-lg pl-4 pr-10 py-3 focus:outline-none focus:border-indigo-500 transition shadow-sm"
          />
          <button 
            type="submit"
            disabled={!input.trim() || isTyping}
            className="absolute right-2 top-1/2 -translate-y-1/2 text-zinc-400 hover:text-indigo-400 disabled:opacity-50 p-2"
          >
            <Icon name="paper-plane" />
          </button>
        </div>
        <div className="text-[10px] text-zinc-600 mt-2 text-center">
          {complexity === 'low' && "⚡ Using gemini-2.5-flash-lite for instant answers"}
          {complexity === 'high' && "🧠 Using gemini-3-pro with thinking capability"}
          {complexity === 'research' && "📚 Using gemini-3-flash for detailed research"}
        </div>
      </form>
    </div>
  );
};

// --- Main App Logic ---

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [projects, setProjects] = useState<Project[]>([]);
  const [activeProject, setActiveProject] = useState<Project | null>(null);
  const [files, setFiles] = useState<File[]>([]);
  const [activeFile, setActiveFile] = useState<File | null>(null);
  const [consoleOutput, setConsoleOutput] = useState("");
  const [chatMessages, setChatMessages] = useState<ChatMessage[]>([]);
  const [isAiTyping, setIsAiTyping] = useState(false);

  // Load User / Session
  useEffect(() => {
    // Simple persistent session mock
    const savedUser = localStorage.getItem('thiia_user');
    if (savedUser) {
      setUser(JSON.parse(savedUser));
    }
  }, []);

  // Load Projects on Auth
  useEffect(() => {
    if (user) {
      setProjects(db.getProjects());
    }
  }, [user]);

  // Load Files when Project Changes
  useEffect(() => {
    if (activeProject) {
      const pFiles = db.getFiles(activeProject.id);
      setFiles(pFiles);
      if (pFiles.length > 0) setActiveFile(pFiles[0]);
      setConsoleOutput("");
      setChatMessages([{
        id: 'welcome',
        role: 'assistant',
        content: `Welcome to project ${activeProject.name}! I'm ready to help you code.`,
        model: 'system',
        timestamp: Date.now()
      }]);
    } else {
      setFiles([]);
      setActiveFile(null);
    }
  }, [activeProject]);

  const handleLogin = () => {
    const mockUser: User = { id: 'u1', name: 'Developer', email: 'dev@thiia.ai' };
    localStorage.setItem('thiia_user', JSON.stringify(mockUser));
    setUser(mockUser);
  };

  const handleLogout = () => {
    localStorage.removeItem('thiia_user');
    setUser(null);
    setActiveProject(null);
  };

  const handleCreateProject = () => {
    const name = prompt("Project Name:");
    if (!name) return;
    const newProj = db.createProject(name, "New Project", "javascript");
    setProjects(db.getProjects());
    setActiveProject(newProj);
  };

  const handleCreateFile = () => {
    if (!activeProject) return;
    const name = prompt("File Name (e.g. script.js):");
    if (!name) return;
    const newFile = db.createFile(activeProject.id, name, "javascript");
    setFiles(db.getFiles(activeProject.id));
    setActiveFile(newFile);
  };

  const handleFileChange = (newContent: string) => {
    if (!activeFile) return;
    const updated = { ...activeFile, content: newContent };
    setActiveFile(updated);
    // Update local list for immediate reflection
    setFiles(files.map(f => f.id === activeFile.id ? updated : f));
    // Persist
    db.updateFileContent(activeFile.id, newContent);
  };

  const executeCode = async () => {
    if (!activeFile) return;
    setConsoleOutput("Running...");

    // Simulate execution delay
    await new Promise(r => setTimeout(r, 600));

    try {
      if (activeFile.language === 'javascript') {
        // Safe-ish eval for demo
        let logs: string[] = [];
        const mockConsole = {
          log: (...args: any[]) => logs.push(args.map(a => String(a)).join(' '))
        };
        // eslint-disable-next-line no-new-func
        const run = new Function('console', activeFile.content);
        run(mockConsole);
        setConsoleOutput(logs.join('\n') || "No output.");
      } else {
        setConsoleOutput(`[Mock Interpreter]\nExecuting ${activeFile.language}...\n\nOutput:\n> Hello from the simulated backend!`);
      }
    } catch (e: any) {
      setConsoleOutput(`Error: ${e.message}`);
    }
  };

  const handleSendMessage = async (text: string, complexity: AIComplexity) => {
    const userMsg: ChatMessage = {
      id: crypto.randomUUID(),
      role: 'user',
      content: text,
      model: 'user',
      timestamp: Date.now()
    };

    setChatMessages(prev => [...prev, userMsg]);
    setIsAiTyping(true);

    const context = activeFile ? `Current File: ${activeFile.name}\nLanguage: ${activeFile.language}\nContent:\n${activeFile.content}` : "No file selected.";

    // Convert internal message format to history for service
    // For now we just send prompt + context to generateResponse

    const aiText = await generateResponse(text, context, complexity);

    setIsAiTyping(false);

    const aiMsg: ChatMessage = {
      id: crypto.randomUUID(),
      role: 'assistant',
      content: aiText,
      model: complexity === 'high' ? 'gemini-3-pro' : complexity === 'research' ? 'gemini-3-flash' : 'gemini-2.5-flash-lite',
      timestamp: Date.now()
    };

    setChatMessages(prev => [...prev, aiMsg]);
  };

  if (!user) {
    return (
      <div className="h-full w-full bg-zinc-950 flex flex-col items-center justify-center relative overflow-hidden">
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_50%_120%,rgba(79,70,229,0.2),rgba(0,0,0,0))]" />

        <div className="z-10 text-center space-y-8 p-8 max-w-md w-full">
          <div className="flex justify-center mb-6">
            <div className="h-20 w-20 bg-indigo-500/10 rounded-2xl flex items-center justify-center border border-indigo-500/20 shadow-xl shadow-indigo-500/10">
               <Icon name="code-branch" className="text-4xl text-indigo-400" />
            </div>
          </div>

          <div className="space-y-2">
            <h1 className="text-4xl font-bold tracking-tight text-white">Thiia AI</h1>
            <p className="text-zinc-400">Next-gen AI Development Environment</p>
          </div>

          <div className="space-y-4 pt-4">
            <button 
              onClick={handleLogin}
              className="w-full bg-white text-black py-3 rounded-lg font-medium hover:bg-gray-100 transition flex items-center justify-center gap-3"
            >
              <Icon name="github" className="text-xl" />
              Continue with GitHub
            </button>
            <button 
              onClick={handleLogin}
              className="w-full bg-[#1a1a1a] border border-zinc-800 text-white py-3 rounded-lg font-medium hover:bg-zinc-800 transition flex items-center justify-center gap-3"
            >
              <Icon name="google" className="text-xl" />
              Continue with Google
            </button>
          </div>

          <p className="text-xs text-zinc-600 pt-8">
            Powered by Gemini 2.5 Flash Lite & 3 Pro
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen w-screen bg-zinc-950 text-gray-200 font-sans">
      <Sidebar 
        projects={projects}
        activeProject={activeProject}
        onSelectProject={setActiveProject}
        onCreateProject={handleCreateProject}
        onLogout={handleLogout}
      />

      {activeProject ? (
        <>
          <FileTree 
            files={files}
            activeFile={activeFile}
            onSelectFile={setActiveFile}
            onCreateFile={handleCreateFile}
          />

          <div className="flex-1 flex flex-col min-w-0">
            {/* Editor Toolbar */}
            <div className="h-12 bg-zinc-900 border-b border-zinc-800 flex items-center justify-between px-4">
               <div className="flex items-center gap-2 text-sm">
                 <span className="text-zinc-500">{activeProject.name}</span>
                 <span className="text-zinc-700">/</span>
                 <span className="text-zinc-200 font-medium">{activeFile?.name}</span>
               </div>
               <button 
                 onClick={executeCode}
                 className="flex items-center gap-2 bg-green-700 hover:bg-green-600 text-white px-4 py-1.5 rounded text-sm transition font-medium"
               >
                 <Icon name="play" className="text-xs" />
                 Run
               </button>
            </div>

            <div className="flex-1 flex flex-col min-h-0">
               <CodeEditor file={activeFile} onChange={handleFileChange} />
               <Console output={consoleOutput} />
            </div>
          </div>

          <ChatInterface 
            messages={chatMessages}
            onSendMessage={handleSendMessage}
            isTyping={isAiTyping}
          />
        </>
      ) : (
        <div className="flex-1 flex flex-col items-center justify-center text-zinc-500 bg-zinc-950">
          <div className="w-16 h-16 bg-zinc-900 rounded-full flex items-center justify-center mb-4">
             <Icon name="layer-group" className="text-2xl opacity-50" />
          </div>
