export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [projects, setProjects] = useState<Project[]>([]);
  const [activeProject, setActiveProject] = useState<Project | null>(null);
  const [files, setFiles] = useState<File[]>([]);
  const [activeFile, setActiveFile] = useState<File | null>(null);
  const [consoleOutput, setConsoleOutput] = useState("");
  const [chatMessages, setChatMessages] = useState<ChatMessage[]>([]);
  const [isAiTyping, setIsAiTyping] = useState(false);

  // Debug State
  const [debugState, setDebugState] = useState<DebugState>({
    isActive: false,
    isPaused: false,
    currentStepIndex: -1,
    trace: [],
    breakpoints: [],
    variables: {}
  });

  // Load User / Session
  useEffect(() => {
    const savedUser = localStorage.getItem('thiia_user');
    if (savedUser) {
      setUser(JSON.parse(savedUser));
    }
  }, []);

  // Load Projects on Auth
  useEffect(() => {
    if (user) {
      setProjects(db.getProjects());
    }
  }, [user]);

  // Load Files when Project Changes
  useEffect(() => {
    if (activeProject) {
      const pFiles = db.getFiles(activeProject.id);
      setFiles(pFiles);
      if (pFiles.length > 0) setActiveFile(pFiles[0]);
      setConsoleOutput("");
      setChatMessages([{
        id: 'welcome',
        role: 'assistant',
        content: `Welcome to project ${activeProject.name}! I'm ready to help you code.`,
        model: 'system',
        timestamp: Date.now()
      }]);
      // Reset Debug state on project switch
      setDebugState({
        isActive: false,
        isPaused: false,
        currentStepIndex: -1,
        trace: [],
        breakpoints: [],
        variables: {}
      });
    } else {
      setFiles([]);
      setActiveFile(null);
    }
  }, [activeProject]);

  const handleLogin = () => {
    const mockUser: User = { id: 'u1', name: 'Developer', email: 'dev@thiia.ai' };
    localStorage.setItem('thiia_user', JSON.stringify(mockUser));
    setUser(mockUser);
  };

  const handleLogout = () => {
    localStorage.removeItem('thiia_user');
    setUser(null);
    setActiveProject(null);
  };

  const handleCreateProject = () => {
    const name = prompt("Project Name:");
    if (!name) return;
    const newProj = db.createProject(name, "New Project", "javascript");
    setProjects(db.getProjects());
    setActiveProject(newProj);
  };

  const handleCreateFile = () => {
    if (!activeProject) return;
    const name = prompt("File Name (e.g. script.js):");
    if (!name) return;
    const newFile = db.createFile(activeProject.id, name, "javascript");
    setFiles(db.getFiles(activeProject.id));
    setActiveFile(newFile);
  };

  const handleFileChange = (newContent: string) => {
    if (!activeFile) return;
    const updated = { ...activeFile, content: newContent };
    setActiveFile(updated);
    setFiles(files.map(f => f.id === activeFile.id ? updated : f));
    db.updateFileContent(activeFile.id, newContent);

    // If editing, stop debug
    if (debugState.isActive) {
      setDebugState(prev => ({ ...prev, isActive: false, trace: [], currentStepIndex: -1 }));
    }
  };

  const handleToggleBreakpoint = (line: number) => {
    setDebugState(prev => {
      const exists = prev.breakpoints.includes(line);
      return {
        ...prev,
        breakpoints: exists 
          ? prev.breakpoints.filter(b => b !== line) 
          : [...prev.breakpoints, line]
      };
    });
  };

  const startDebugging = async () => {
    if (!activeFile) return;
    setConsoleOutput("Initializing debugger (AI Simulation)...\nGenerating execution trace...");

    // Reset state but keep breakpoints
    setDebugState(prev => ({ 
      ...prev, 
      isActive: true, 
      isPaused: true, 
      currentStepIndex: -1, 
      trace: [],
      variables: {} 
    }));

    const trace = await generateDebugTrace(activeFile.content, activeFile.language);

    if (trace.length === 0) {
      setConsoleOutput("Debugger failed to initialize or code produced no trace.");
      setDebugState(prev => ({ ...prev, isActive: false }));
      return;
    }

    setDebugState(prev => ({
      ...prev,
      trace,
      currentStepIndex: 0,
      isPaused: true, // Start paused at first line
      variables: trace[0].variables,
    }));
    setConsoleOutput(`Debugger started.\nPaused at line ${trace[0].line}.`);
  };

  const handleDebugAction = (action: 'step' | 'continue' | 'stop') => {
    if (!debugState.isActive || !debugState.trace.length) return;

    if (action === 'stop') {
      setDebugState(prev => ({ 
        ...prev, 
        isActive: false, 
        currentStepIndex: -1,
        trace: [],
        variables: {}
      }));
      setConsoleOutput(prev => prev + "\nDebugger stopped.");
      return;
    }

    let nextIndex = debugState.currentStepIndex + 1;
    let hitBreakpoint = false;
    let outputAccumulator = "";

    if (action === 'step') {
      // Just one step
      if (nextIndex >= debugState.trace.length) {
        setConsoleOutput(prev => prev + "\nExecution finished.");
        setDebugState(prev => ({ ...prev, isActive: false, currentStepIndex: -1 }));
        return;
      }
    } else if (action === 'continue') {
      // Loop until breakpoint or end
      while (nextIndex < debugState.trace.length) {
        const step = debugState.trace[nextIndex];
        if (step.output) outputAccumulator += step.output + "\n";

        // Check breakpoint (skip the very first line if we are just starting continue)
        if (debugState.breakpoints.includes(step.line)) {
          hitBreakpoint = true;
          break;
        }

        // If not breaking, we continue loop, but we need to update 'last known' index
        // Actually, continue should run fast.
        if (!hitBreakpoint) {
           nextIndex++;
        }
      }
      // If loop finished because we ran out of trace
      if (nextIndex >= debugState.trace.length) {
         setConsoleOutput(prev => prev + "\n" + outputAccumulator + "Execution finished.");
         setDebugState(prev => ({ ...prev, isActive: false, currentStepIndex: -1 }));
         return;
      }
    }

    // Update state to new index (either step result or breakpoint hit)
    const nextStep = debugState.trace[nextIndex]; // Correction: if continue hit BP, nextIndex is the BP line index

    // Note: If 'continue' ran multiple steps, we only show output now. 
    // If 'step' ran, we show output.
    if (action === 'step' && nextStep.output) {
      outputAccumulator = nextStep.output + "\n";
    }

    setConsoleOutput(prev => prev + outputAccumulator);
    setDebugState(prev => ({
      ...prev,
      currentStepIndex: nextIndex,
      variables: nextStep.variables,
      isPaused: true
    }));
  };

  const executeCode = async () => {
    if (!activeFile) return;
    setConsoleOutput("Running...");
    await new Promise(r => setTimeout(r, 600));

    try {
      if (activeFile.language === 'javascript') {
        let logs: string[] = [];
        const mockConsole = {
          log: (...args: any[]) => logs.push(args.map(a => String(a)).join(' '))
        };
        // eslint-disable-next-line no-new-func
        const run = new Function('console', activeFile.content);
        run(mockConsole);
        setConsoleOutput(logs.join('\n') || "No output.");
      } else {
        setConsoleOutput(`[Mock Interpreter]\nExecuting ${activeFile.language}...\n\nOutput:\n> Hello from the simulated backend!`);
      }
    } catch (e: any) {
      setConsoleOutput(`Error: ${e.message}`);
    }
  };

  const handleSendMessage = async (text: string, complexity: AIComplexity) => {
    const userMsg: ChatMessage = {
      id: crypto.randomUUID(),
      role: 'user',
      content: text,
      model: 'user',
      timestamp: Date.now()
    };

    setChatMessages(prev => [...prev, userMsg]);
    setIsAiTyping(true);

    const context = activeFile ? `Current File: ${activeFile.name}\nLanguage: ${activeFile.language}\nContent:\n${activeFile.content}` : "No file selected.";
    const aiText = await generateResponse(text, context, complexity);

    setIsAiTyping(false);

    const aiMsg: ChatMessage = {
      id: crypto.randomUUID(),
      role: 'assistant',
      content: aiText,
      model: complexity === 'high' ? 'gemini-3-pro' : complexity === 'research' ? 'gemini-3-flash' : 'gemini-2.5-flash-lite',
      timestamp: Date.now()
    };

    setChatMessages(prev => [...prev, aiMsg]);
  };

